    EVOLUTION_URL: 'https://evo.vortekai.es',
    EVOLUTION_INSTANCE: 'Ventas vortek',
    WHATSAPP_NUMBER: '34628706539',
  }
}];

const config = $input.first().json;
const now = new Date();

// Calcular fecha de Madrid correctamente usando offset UTC
// Madrid: UTC+1 en invierno, UTC+2 en verano (CET/CEST)
function getMadridDate(date) {
  const madridStr = date.toLocaleString('en-CA', { timeZone: 'Europe/Madrid', year: 'numeric', month: '2-digit', day: '2-digit' });
  return madridStr; // returns YYYY-MM-DD
}
function getMadridMidnightUTC(dateStr) {
  // Calcula la medianoche de Madrid en UTC
  const d = new Date(dateStr + 'T00:00:00');
  const madridOffset = new Date(d.toLocaleString('en-US', { timeZone: 'Europe/Madrid' })) - new Date(d.toLocaleString('en-US', { timeZone: 'UTC' }));
  return new Date(d.getTime() - madridOffset).toISOString();
}

const todayStr = getMadridDate(now);
const startISO = getMadridMidnightUTC(todayStr);
const tomorrow = new Date(todayStr + 'T00:00:00');
tomorrow.setDate(tomorrow.getDate() + 1);
const tomorrowStr = tomorrow.toISOString().split('T')[0];
const endISO = getMadridMidnightUTC(tomorrowStr);

const headers = { 'apikey': config.SUPABASE_KEY, 'Authorization': `Bearer ${config.SUPABASE_KEY}` };

// Proyectos hoy
const projResp = await fetch(
  `${config.SUPABASE_URL}/rest/v1/workana_projects?select=id,status,relevance_score&created_at=gte.${startISO}&created_at=lt.${endISO}`,
  { headers }
);
const projects = await projResp.json();

// Propuestas hoy
const propResp = await fetch(
  `${config.SUPABASE_URL}/rest/v1/workana_proposals?select=id,budget_suggested&created_at=gte.${startISO}&created_at=lt.${endISO}`,
  { headers }
);
const proposals = await propResp.json();

// Errores hoy
const errResp = await fetch(
  `${config.SUPABASE_URL}/rest/v1/workana_logs?select=id&created_at=gte.${startISO}&created_at=lt.${endISO}&success=eq.false`,
  { headers }
);
const errors = await errResp.json();

// Cuota semanal — calcular lunes de esta semana en hora Madrid
const madridNow = new Date(now.toLocaleString('en-US', { timeZone: 'Europe/Madrid' }));
const dayOfWeek = madridNow.getDay() === 0 ? 7 : madridNow.getDay();
const mondayDate = new Date(madridNow);
mondayDate.setDate(madridNow.getDate() - (dayOfWeek - 1));
const mondayStr = mondayDate.toISOString().split('T')[0];
const weekStartISO = getMadridMidnightUTC(mondayStr);
const weekResp = await fetch(
  `${config.SUPABASE_URL}/rest/v1/workana_proposals?select=id&created_at=gte.${weekStartISO}`,
  { headers }
);
const weekProposals = await weekResp.json();

// Retry queue pendientes
let retryPending = 0;
try {
  const retryResp = await fetch(
    `${config.SUPABASE_URL}/rest/v1/workana_retry_queue?select=id&status=eq.pending`,
    { headers }
  );
  const retryItems = await retryResp.json();
  retryPending = Array.isArray(retryItems) ? retryItems.length : 0;
} catch (e) { /* tabla puede no existir aún */ }

const totalProjects = Array.isArray(projects) ? projects.length : 0;
const totalProposals = Array.isArray(proposals) ? proposals.length : 0;
const totalErrors = Array.isArray(errors) ? errors.length : 0;
const weekTotal = Array.isArray(weekProposals) ? weekProposals.length : 0;
const sent = Array.isArray(projects) ? projects.filter(p => p.status === 'sent').length : 0;
const skipped = Array.isArray(projects) ? projects.filter(p => p.status === 'skipped').length : 0;
const avgRelevance = totalProjects > 0
  ? Math.round(projects.reduce((sum, p) => sum + (p.relevance_score || 0), 0) / totalProjects)
  : 0;
const totalBudget = Array.isArray(proposals)
  ? proposals.reduce((sum, p) => sum + (p.budget_suggested || 0), 0)
  : 0;

const relevanceBar = '█'.repeat(Math.floor(avgRelevance / 10)) + '░'.repeat(10 - Math.floor(avgRelevance / 10));

const msg = `📊 *RESUMEN DIARIO - ${todayStr}*

📋 Proyectos analizados: ${totalProjects}
✅ Propuestas generadas: ${totalProposals}
📨 Enviadas auto: ${sent}
⏭️ Descartados: ${skipped}
❌ Errores: ${totalErrors}
🔄 En cola de reintento: ${retryPending}
🎯 Relevancia media: ${relevanceBar} ${avgRelevance}/100
💶 Valor total propuestas: €${totalBudget}

📅 *Cuota semanal:* ${weekTotal} propuestas

${totalErrors > 3 ? '⚠️ Demasiados errores hoy. Revisa los logs.' : '✅ Sistema operando correctamente.'}`;

return [{
  json: {
    ...config,
    message: msg,
  }
}];
